# Script autonomo: inyecta PanaderiasOutbound y lo coloca dentro de ClientesView
$path = "C:\Users\josec\Downloads\astra-hq-nextjs\astra-hq\pages\index.js"
$c = [System.IO.File]::ReadAllText($path, [System.Text.Encoding]::UTF8)

$b64 = ""
$comp = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String($b64))

# PASO 1: inyectar la definicion del componente antes de ClientesView
$anchor1 = "function ClientesView({ realData }) {"
if ($c.Contains($anchor1) -and -not $c.Contains("function PanaderiasOutbound")) {
  $c = $c.Replace($anchor1, $comp + $anchor1)
  Write-Host "1 OK: componente inyectado" -ForegroundColor Green
} elseif ($c.Contains("function PanaderiasOutbound")) {
  Write-Host "1 OK: ya existia" -ForegroundColor Green
} else {
  Write-Host "1 FALLO: no encontre ClientesView" -ForegroundColor Red
}

# PASO 2: colocar <PanaderiasOutbound /> dentro del return, entre los dos </div> de cierre
$marker = "Sin DMs registrados. Activa el Flujo 2 en n8n.</div>}"
$idx = $c.IndexOf($marker)
if ($idx -ge 0 -and -not $c.Contains("<PanaderiasOutbound")) {
  $cbCRLF = "</div>" + [char]13 + [char]10 + "    </div>" + [char]13 + [char]10 + "  );"
  $cb = $c.IndexOf($cbCRLF, $idx)
  if ($cb -ge 0) {
    $newCRLF = "</div>" + [char]13 + [char]10 + "      <PanaderiasOutbound realData={realData} />" + [char]13 + [char]10 + "    </div>" + [char]13 + [char]10 + "  );"
    $c = $c.Substring(0, $cb) + $newCRLF + $c.Substring($cb + $cbCRLF.Length)
    Write-Host "2 OK: colocado (CRLF)" -ForegroundColor Green
  } else {
    $cbLF = "</div>" + [char]10 + "    </div>" + [char]10 + "  );"
    $cb2 = $c.IndexOf($cbLF, $idx)
    if ($cb2 -ge 0) {
      $newLF = "</div>" + [char]10 + "      <PanaderiasOutbound realData={realData} />" + [char]10 + "    </div>" + [char]10 + "  );"
      $c = $c.Substring(0, $cb2) + $newLF + $c.Substring($cb2 + $cbLF.Length)
      Write-Host "2 OK: colocado (LF)" -ForegroundColor Green
    } else {
      Write-Host "2 FALLO: no encontre el cierre" -ForegroundColor Red
    }
  }
} elseif ($c.Contains("<PanaderiasOutbound")) {
  Write-Host "2 OK: ya estaba" -ForegroundColor Green
} else {
  Write-Host "2 FALLO: no encontre el marker" -ForegroundColor Red
}

# Guardar en UTF-8 sin BOM
$utf8 = New-Object System.Text.UTF8Encoding $false
[System.IO.File]::WriteAllText($path, $c, $utf8)
Write-Host "Guardado UTF-8 sin BOM." -ForegroundColor Cyan

# Verificacion final
$v = [System.IO.File]::ReadAllText($path, [System.Text.Encoding]::UTF8)
Write-Host "--- VERIFICACION ---" -ForegroundColor Yellow
$clinica = [char]0x43 + 'l' + [char]0x00ED + 'nica'
Write-Host "Acentos: $($v.Contains($clinica))"
Write-Host "Def: $($v.Contains('function PanaderiasOutbound'))"
Write-Host "Usado: $($v.Contains('<PanaderiasOutbound'))"
